formulas.area:
function(inputs) {
  const { side1, side2, side3, base, height, angle } = inputs;
  if (side1 > 0 && side2 > 0 && angle > 0) {
    const rad = angle * Math.PI / 180;
    const area = 0.5 * side1 * side2 * Math.sin(rad);
    const steps = 'SAS: 0.5 x ' + side1 + ' x ' + side2 + ' x sin(' + angle + '°) = ' + area.toFixed(4) + ' m²';
    return { area: area, method: 'SAS (Side-Angle-Side)', steps: steps };
  } else if (base > 0 && height > 0) {
    const area = 0.5 * base * height;
    const steps = 'Base-Height: 0.5 x ' + base + ' x ' + height + ' = ' + area.toFixed(4) + ' m²';
    return { area: area, method: 'Base & Height', steps: steps };
  } else if (side1 > 0 && side2 > 0 && side3 > 0) {
    const s = (side1 + side2 + side3) / 2;
    const area = Math.sqrt(s * (s - side1) * (s - side2) * (s - side3));
    if (isNaN(area)) {
      return { area: 0, method: 'Invalid sides', steps: 'Side lengths do not form a valid triangle.' };
    }
    const steps = 'Heron: s = (' + side1 + '+' + side2 + '+' + side3 + ')/2 = ' + s.toFixed(4) + '; area = √[s(s-a)(s-b)(s-c)] = ' + area.toFixed(4) + ' m²';
    return { area: area, method: 'Heron formula', steps: steps };
  } else {
    return { area: 0, method: 'Insufficient inputs', steps: 'Provide base & height, three sides, or two sides and included angle.' };
  }
}
